                 I.getPredicate() == FCmpInst::FCMP_ULE ||
                 I.getPredicate() == FCmpInst::FCMP_OLT ||
                 I.getPredicate() == FCmpInst::FCMP_ULT);

  if ((IsGreater || IsLess) && !C->isNaN()) {
    bool NextDown = false;
    if (I.getPredicate() == FCmpInst::FCMP_OGE ||
