            Pred = FCmpInst::FCMP_ULE;
          else if (Pred == FCmpInst::FCMP_OGT)
            Pred = FCmpInst::FCMP_OGE;
          else if (Pred == FCmpInst::FCMP_UGT)
            Pred = FCmpInst::FCMP_UGE;
        }
      }
      return new FCmpInst(Pred, X, ConstantFP::get(X->getType(), Mid), "", &I);
