  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    if (match(Op1, m_FPTrunc(m_Value(Y))) && X->getType() == Y->getType())
      return new FCmpInst(Pred, X, Y, "", &I);

    const APFloat *C;
    if (match(Op1, m_APFloat(C))) {
      // fcmp (fptrunc x), C -> fcmp x, C'
      const fltSemantics &XSem = X->getType()->getScalarType()->getFltSemantics();
      bool IsGreater = (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
                        Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT);
      bool IsLess = (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE ||
                     Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT);

      if ((IsGreater || IsLess) && !C->isNaN()) {
        bool NextDown = false;
        if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
            Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT) {
            // (fptrunc X) >= C  <=> X >= Mid(C, nextDown(C))
            // (fptrunc X) < C   <=> X < Mid(C, nextDown(C))
            NextDown = true;
        } else {
            // (fptrunc X) <= C  <=> X <= Mid(C, nextUp(C))
            // (fptrunc X) > C   <=> X > Mid(C, nextUp(C))
            NextDown = false;
        }

        APFloat Bound = *C;
        Bound.next(NextDown);

        // Handle the case when Bound is infinity (C is max/min representable float)
        if (Bound.isInfinity()) {
          // When C is the max representable float and Pred is OGT:
          // (fptrunc X) > max_float  <=>  X > largest_double_rounding_to_max_float
          // When C is the max representable float and Pred is OLE:
          // (fptrunc X) <= max_float  <=>  X <= largest_double_rounding_to_max_float
          // Similar logic applies for min representable float.
          bool Lossy;
          APFloat CExt = *C;
          CExt.convert(XSem, APFloat::rmNearestTiesToEven, &Lossy);

          // Find the threshold: the largest/smallest double that rounds to C
          APFloat Threshold = CExt;
          if (NextDown) {
            // For OGE/OLT with C being smallest positive float, or OLE/OGT with C being largest negative float
            // Threshold is the smallest double that rounds to C
            // We need to find the boundary between doubles that round to 0 and doubles that round to C
            // This is the midpoint between 0 and C in double precision
            APFloat Zero(XSem, "0.0");
            APFloat Mid = CExt;
            Mid.add(Zero, APFloat::rmNearestTiesToEven);
            APFloat Two(XSem, "2.0");
            Mid.divide(Two, APFloat::rmNearestTiesToEven);

            // Check if C is positive or negative
            if (C->isNegative()) {
              // For negative C, we need to adjust the predicate
              // (fptrunc X) <= C  <=>  X <= Mid (if C is negative max)
              // (fptrunc X) > C   <=>  X > Mid (if C is negative max)
              return new FCmpInst(Pred, X, ConstantFP::get(X->getType(), Mid), "", &I);
            } else {
              // For positive C (smallest positive denormal)
              // (fptrunc X) >= C  <=>  X >= Mid
              // (fptrunc X) < C   <=>  X < Mid
              return new FCmpInst(Pred, X, ConstantFP::get(X->getType(), Mid), "", &I);
            }
          } else {
            // For OGT/OLE with C being max float, or OLT/OGE with C being min float
            // Threshold is the largest double that rounds to C
            // We need to find the boundary between doubles that round to C and doubles that round to inf
            // This is the midpoint between C and nextUp(C) in double precision
            // But nextUp(C) is inf, so we need to handle this specially

            // The threshold is the largest double that rounds to C
            // This is CExt + (nextUp(CExt) - CExt) / 2 - epsilon
            // But since nextUp(C) is inf, we use a different approach

            // Actually, for OGT with max_float:
            // (fptrunc X) > max_float  <=>  X > largest_double_rounding_to_max_float
            // The largest double rounding to max_float is the one just below the threshold to inf

            // Let's compute the threshold more carefully
            // The threshold is the value that separates doubles rounding to C from doubles rounding to inf
            // This is the midpoint between CExt and nextUp(CExt)
            APFloat NextUpCExt = CExt;
            NextUpCExt.next(false);  // nextUp

            APFloat Mid = CExt;
            Mid.add(NextUpCExt, APFloat::rmNearestTiesToEven);
            APFloat Two(XSem, "2.0");
            Mid.divide(Two, APFloat::rmNearestTiesToEven);

            // Adjust predicate based on whether we're including or excluding the threshold
            CmpInst::Predicate NewPred = Pred;
            if (Pred == FCmpInst::FCMP_OGT)
              NewPred = FCmpInst::FCMP_OGT;  // X > Mid
            else if (Pred == FCmpInst::FCMP_UGT)
              NewPred = FCmpInst::FCMP_UGT;
            else if (Pred == FCmpInst::FCMP_OLE)
              NewPred = FCmpInst::FCMP_OLE;  // X <= Mid
            else if (Pred == FCmpInst::FCMP_ULE)
              NewPred = FCmpInst::FCMP_ULE;
            else if (Pred == FCmpInst::FCMP_OLT)
              NewPred = FCmpInst::FCMP_OLT;  // X < Mid
            else if (Pred == FCmpInst::FCMP_ULT)
              NewPred = FCmpInst::FCMP_ULT;
            else if (Pred == FCmpInst::FCMP_OGE)
              NewPred = FCmpInst::FCMP_OGE;  // X >= Mid
            else if (Pred == FCmpInst::FCMP_UGE)
              NewPred = FCmpInst::FCMP_UGE;

            return new FCmpInst(NewPred, X, ConstantFP::get(X->getType(), Mid), "", &I);
          }
        }

        bool Lossy;
        APFloat BoundExt = Bound;
        BoundExt.convert(XSem, APFloat::rmNearestTiesToEven, &Lossy);

        APFloat CExt = *C;
        CExt.convert(XSem, APFloat::rmNearestTiesToEven, &Lossy);

        APFloat Mid = BoundExt;
        Mid.add(CExt, APFloat::rmNearestTiesToEven);
        APFloat Two(XSem, "2.0");
        Mid.divide(Two, APFloat::rmNearestTiesToEven);

        APFloat TruncMid = Mid;
        TruncMid.convert(C->getSemantics(), APFloat::rmNearestTiesToEven, &Lossy);

        bool MidRoundsToC = TruncMid.bitwiseIsEqual(*C);
        bool MidRoundsToBound = TruncMid.bitwiseIsEqual(Bound);

        if (MidRoundsToC || MidRoundsToBound) {
          if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
              Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE) {
             // OGE: (fptrunc X) >= C  <=> X >= Mid (if Mid rounds to C)  or X > Mid (if rounds to Bound)
             // OLE: (fptrunc X) <= C  <=> X <= Mid (if Mid rounds to C)  or X < Mid (if rounds to Bound)
             CmpInst::Predicate NewPred = Pred;
             if (!MidRoundsToC) { // Mid rounds to Bound, so Mid itself is not included.
                 if (Pred == FCmpInst::FCMP_OGE) NewPred = FCmpInst::FCMP_OGT;
                 else if (Pred == FCmpInst::FCMP_UGE) NewPred = FCmpInst::FCMP_UGT;
                 else if (Pred == FCmpInst::FCMP_OLE) NewPred = FCmpInst::FCMP_OLT;
                 else if (Pred == FCmpInst::FCMP_ULE) NewPred = FCmpInst::FCMP_ULT;
             }
             return new FCmpInst(NewPred, X, ConstantFP::get(X->getType(), Mid), "", &I);
          } else {
             // OLT: (fptrunc X) < C   <=> X < Mid (if Mid rounds to C)  or X <= Mid (if rounds to Bound)
             // OGT: (fptrunc X) > C   <=> X > Mid (if Mid rounds to C)  or X >= Mid (if rounds to Bound)
             CmpInst::Predicate NewPred = Pred;
             if (!MidRoundsToC) { // Mid rounds to Bound, so Mid itself IS included.
                 if (Pred == FCmpInst::FCMP_OLT) NewPred = FCmpInst::FCMP_OLE;
                 else if (Pred == FCmpInst::FCMP_ULT) NewPred = FCmpInst::FCMP_ULE;
                 else if (Pred == FCmpInst::FCMP_OGT) NewPred = FCmpInst::FCMP_OGE;
                 else if (Pred == FCmpInst::FCMP_UGT) NewPred = FCmpInst::FCMP_UGE;
             }
             return new FCmpInst(NewPred, X, ConstantFP::get(X->getType(), Mid), "", &I);
          }
        }
      }
    }
  }
